import novamind_api as nm, random, math, statistics, json
DAY=nm.vars.current_day
cash0=float(nm.query('SELECT SUM(amount) cash FROM ledger')['rows'][0]['cash'])
rows=nm.query(f"""
SELECT c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2) price,s.billing_day_mod30,s.start_day,COUNT(*) n,SUM(s.seat_count) seats
FROM subscriptions s JOIN customers c USING(customer_id)
WHERE s.status IN ('active','subscribed')
GROUP BY c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2),s.billing_day_mod30,s.start_day
""")['rows']
coh=[]; ent=[]
for r in rows:
    rec={'g':r['group_id'],'type':r['customer_type'],'plan':r['plan'],'price':float(r['price']),'mod':int(r['billing_day_mod30']),'start':int(r['start_day']),'n':float(r['n']),'seats':float(r['seats'] or r['n'])}
    (ent if r['customer_type']=='large' else coh).append(rec)
pipe=nm.query("""
WITH latest AS (
  SELECT et.* FROM enterprise_turns et
  JOIN (SELECT customer_id, MAX(message_id) mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id) m ON et.customer_id=m.customer_id AND et.message_id=m.mid
), firsts AS (SELECT customer_id, MIN(day) first_day, MAX(seat_count) seats FROM enterprise_turns GROUP BY customer_id)
SELECT latest.customer_id,c.group_id,latest.sender,latest.turn_number,latest.day latest_day, firsts.first_day, firsts.seats, latest.offer_json, s.status
FROM latest JOIN firsts USING(customer_id) JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE latest.closed=0 AND c.customer_type='large' AND s.status='lead' AND latest.sender='agent'
""")['rows']
usage=nm.query(f"""
SELECT c.group_id,s.plan, SUM(du.usage_units) usage
FROM daily_usage du JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE du.day>{DAY-7} AND du.day<= {DAY} AND s.status IN ('active','subscribed')
GROUP BY c.group_id,s.plan
""")['rows']
rate_cost={'A':0.002,'B':0.006,'C':0.012}
active_counts={}
for c in coh+ent:
    active_counts[(c['g'],c['plan'])]=active_counts.get((c['g'],c['plan']),0)+c['seats']
comp_per_seat_day={}
for r in usage:
    key=(r['group_id'],r['plan']); act=max(active_counts.get(key,1),1)
    comp_per_seat_day[key]=float(r['usage'])*rate_cost.get(r['plan'],0.006)/7.0/act
print('cash0',round(cash0),'small active',sum(c['n'] for c in coh),'mrr',round(sum(c['price']*c['seats'] for c in coh)),'ent seats',sum(e['seats'] for e in ent),'pipe n,seats',len(pipe),sum(float(p['seats'] or 0) for p in pipe))

# Actions day266: ops 299.6k, dev 69.5k, ads 20k, capacity 28k. t10 cost already deducted.
fixed_per_day=299600+69500+20000+28000
leadcost_per_day=650
T8_DAY=294; T8_BOOST=0.7257
T10_DAY=296; T10_BOOST=1.7232
T9_DAY=375; T9_BOOST=0.2201

def quality_recovery(day):
    # Retention/conversion adder, not raw quality. Current week had fresh competitor shocks/support noise.
    # Higher S2 dev slowly repairs quality before the sampled t8/t10 jumps; t8+t10 materially improve retention after day296.
    if day < T8_DAY:
        return -0.035 + 0.0009*(day-DAY)
    elif day < T10_DAY:
        return 0.025
    elif day < T9_DAY:
        return 0.115
    else:
        return 0.125

def new_cash_and_cohorts(day, active_s2, active_d7, rng, scenario=0.0):
    rec=quality_recovery(day)
    paid=max(0,rng.gauss(290,65))        # raw paid S2 leads/day at $20k/d, calibrated to day260-266
    net=max(0,rng.gauss(185*(active_s2/147000)**0.55,55))
    raw_s2=paid+net
    conv=max(0.58,min(0.97,rng.gauss(0.835 + rec + scenario*0.018,0.06)))
    active=raw_s2*conv
    a=max(0.34,min(0.58,rng.gauss(0.46,0.045)))
    cfrac=max(0.001,min(0.008,rng.lognormvariate(math.log(0.0032),0.45)))
    b=max(0,1-a-cfrac)
    nA,nB,nC=active*a,active*b,active*cfrac
    cash=nA*79+nB*159+nC*349
    mod=day%30
    new=[]
    if nA>0: new.append({'g':'S2','type':'small','plan':'A','price':79,'mod':mod,'start':day,'n':nA,'seats':nA})
    if nB>0: new.append({'g':'S2','type':'small','plan':'B','price':159,'mod':mod,'start':day,'n':nB,'seats':nB})
    if nC>0: new.append({'g':'S2','type':'small','plan':'C','price':349,'mod':mod,'start':day,'n':nC,'seats':nC})
    d7=max(0,rng.gauss(168*(active_d7/24000)**0.35,42))*max(0.72,1+0.65*rec)
    d7a=max(0.50,min(0.75,rng.gauss(0.59,0.06))); d7b=1-d7a
    cash += d7*d7a*19 + d7*d7b*59
    if d7*d7a>0: new.append({'g':'D_S07','type':'small','plan':'A','price':19,'mod':mod,'start':day,'n':d7*d7a,'seats':d7*d7a})
    if d7*d7b>0: new.append({'g':'D_S07','type':'small','plan':'B','price':59,'mod':mod,'start':day,'n':d7*d7b,'seats':d7*d7b})
    other_cash=max(0,rng.gauss(900,500))
    cash += other_cash
    return cash,new,raw_s2+d7+80

def bill_price(g,p,age,stored):
    if g=='S2' and age<45:
        return {'A':44,'B':109,'C':279}.get(p,stored)
    if g=='D_S07':
        return {'A':19,'B':59,'C':289}.get(p,stored)
    return stored

def retention(g,p,age,rng,scenario,day):
    rec=quality_recovery(day)
    if g=='S2':
        if age<45:
            base={'A':0.645,'B':0.945,'C':0.965}.get(p,0.82)+scenario*0.032+rec
        elif age<75:
            base={'A':0.70,'B':0.895,'C':0.965}.get(p,0.86)+scenario*0.030+rec
        else:
            base={'A':0.91,'B':0.955,'C':0.982}.get(p,0.94)+scenario*0.020+0.55*rec
    elif g=='D_S07':
        if age<45:
            base={'A':0.11,'B':0.80,'C':0.94}.get(p,0.55)+scenario*0.035+0.7*rec
        elif age<75:
            base={'A':0.31,'B':0.78,'C':0.94}.get(p,0.70)+scenario*0.035+0.7*rec
        else:
            base={'A':0.70,'B':0.86,'C':0.95}.get(p,0.82)+scenario*0.025+0.4*rec
    elif g=='E3':
        base=0.965+scenario*0.01+max(0,0.35*rec)
    else:
        base=0.78+scenario*0.03+0.20*rec
    return max(0.0,min(0.997,rng.gauss(base,0.025+0.025*(age<45))))

def parse_offer_json(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list):
            return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in data if isinstance(o,dict)]
        if isinstance(data,dict):
            arr=data.get('offers') or data.get('offerings') or []
            if isinstance(arr,list):
                return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in arr if isinstance(o,dict)]
    except Exception: pass
    return []
current_offer_default={
 'E1':[('A',5),('B',11),('C',22)], 'E2':[('A',18),('B',45),('C',89)], 'E3':[('A',20),('B',35),('C',62)],
 'D_E02':[('A',10),('B',24),('C',49)], 'D_E07':[('A',26),('B',49),('C',89)], 'D_E08':[('A',18),('B',40),('C',75)], 'D_E09':[('A',6),('B',16),('C',32)]}

def ent_events(days,rng,scenario):
    events=[]
    mood=max(0.08,min(3.5,rng.lognormvariate(math.log(0.58+0.24*max(scenario,0)),0.85)))
    for p in pipe:
        seats=float(p['seats'] or 0)
        if seats<=0: continue
        g=p['group_id']; age=DAY-int(p['first_day'])
        if g in ('E3','D_E07','D_E08'): mu=0.0065
        elif g in ('E2','D_E02'): mu=0.0045
        else: mu=0.0035
        if age>100: mu*=0.12
        elif age>60: mu*=0.27
        elif age>30: mu*=0.50
        elif age>14: mu*=0.75
        # t8/t10 quality jumps slightly improve enterprise acceptance after day296, especially for quality-sensitive groups
        pclose=max(0,min(0.17, rng.lognormvariate(math.log(max(mu*mood*(1+0.35*max(quality_recovery(DAY+min(days,35)),0)),1e-6)),0.9)))
        if rng.random()<pclose:
            if g in ('E1','D_E09'): delay=max(2,int(rng.gauss(10,7)))
            elif g in ('D_E02','E2'): delay=max(5,int(rng.gauss(24,14)))
            else: delay=max(7,int(rng.gauss(33,18)))
            if delay<=days:
                offers=parse_offer_json(p['offer_json']) or current_offer_default.get(g,current_offer_default['E3'])
                d={k:v for k,v in offers if k and v}
                u=rng.random()
                if g in ('E1','D_E09','D_E02') and 'A' in d and u<0.48: plan='A'
                elif 'B' in d and u<0.88: plan='B'
                elif 'C' in d: plan='C'
                elif 'B' in d: plan='B'
                else: plan='A'
                price=d.get(plan, list(d.values())[0])
                events.append({'day':DAY+delay,'g':g,'type':'large','plan':plan,'price':price,'mod':(DAY+delay)%30,'start':DAY+delay,'n':1,'seats':seats})
    return events

def ent_compute_per_seat_day(g,p):
    if p=='A': base={'E1':0.11,'E2':0.44,'E3':0.25,'D_E02':0.19,'D_E07':0.35,'D_E08':0.24,'D_E09':0.16}.get(g,0.25)
    elif p=='B': base={'E1':0.31,'E2':1.33,'E3':0.74,'D_E02':0.56,'D_E07':1.04,'D_E08':0.72,'D_E09':0.48}.get(g,0.75)
    else: base={'E1':0.62,'E2':2.66,'E3':1.48,'D_E02':1.12,'D_E07':2.08,'D_E08':1.44,'D_E09':0.96}.get(g,1.5)
    return base

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.7,min(1.7,rng.gauss(0,0.6)))
    cash=cash0
    active=[c.copy() for c in coh+ent]
    events=ent_events(days,rng,scenario)
    for day in range(DAY+1,DAY+days+1):
        rel=day-DAY
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        for c in active:
            key=(c['g'],c['plan'])
            if c['type']=='large': comp=ent_compute_per_seat_day(c['g'],c['plan'])
            else: comp=comp_per_seat_day.get(key, {'A':0.33,'B':1.02,'C':1.9}.get(c['plan'],1.0))
            cash -= comp*c['seats']
            if day%30 == c['mod']:
                age=day-c['start']
                ret=retention(c['g'],c['plan'],age,rng,scenario,day)
                kept=c['n']*ret; kept_seats=c['seats']*ret
                if kept>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'])
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        fixed=fixed_per_day
        # after the large R&D boosts land and support is stable, assume some future tuning of spend but keep high support.
        if rel>56:
            s2=sum(c['seats'] for c in active if c['g']=='S2')
            d7=sum(c['seats'] for c in active if c['g']=='D_S07')
            entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops = 5000 + 245000*(max(s2,1)/146000)**0.52 + 30000*(max(d7,1)/24000)**0.60 + 9600
            dev = 5000 + 26000*(max(s2,1)/146000)**0.35 + 3500*(max(d7,1)/24000)**0.35 + 8500
            ads = 20000
            cap = 75000 if entseats>250000 or sum(c['seats'] for c in active)>270000 else 28000
            entops = min(90000, 0.12*max(0,entseats-50000))
            fixed = max(300000,min(590000,ops+dev+ads+cap+entops))
        cash -= fixed
    return cash

for days in [7,28,84,182]:
    nseeds = 320 if days<=28 else (220 if days<=84 else 150)
    vals=[]
    for i in range(nseeds):
        vals.append(simulate(days,38000+i))
    vals.sort(); point=statistics.median(vals); mean=statistics.mean(vals)
    def pct(p): return vals[max(0,min(len(vals)-1,int(p*len(vals))))]
    print('H',days,'mean',round(mean),'median',round(point),'p2.5',round(pct(.025)),'p10',round(pct(.1)),'p90',round(pct(.9)),'p97.5',round(pct(.975)),'min',round(vals[0]),'max',round(vals[-1]))
